  const [showReadings, setShowReadings] = useState(false);

  useEffect(() => {
    fetch("http://localhost:8080/mock/status")
      .then(r => r.json())
      .then(d => setMockAlive(d.alive))
      .catch(() => setMockAlive(false));
  }, []);

